code.C:
#include <stdio.h>
int main(){
    int T = 1;
    for(int i=0;i<T;i++){
        printf("Python provides several classes in the datetime module:\n");
        printf("- date: represents a calendar date (year, month, day) without time. Example: d = date(2023, 7, 3); print(d) -> 2023-07-03.\n");
        printf("- time: represents a time of day (hour, minute, second, microsecond, tzinfo) without a date. Example: t = time(14, 30, 15); print(t) -> 14:30:15.\n");
        printf("- datetime: combines date and time into a single object. Example: dt = datetime(2023,7,3,14,30,15); print(dt) -> 2023-07-03 14:30:15.\n");
        printf("- timedelta: represents a duration, the difference between two dates or times. Supports days, seconds, microseconds, etc. Example: delta = timedelta(days=5, hours=3); new_date = d + delta.\n");
        printf("Differences: date has only year-month-day, time only time-of-day, datetime both, timedelta is a span not a point in time. They are used for different purposes: date for birthdays, time for alarm times, datetime for timestamps, timedelta for adding/subtracting intervals.\n");
    }
    return 0;
}

